const run = $input.first().json;
const config = $('Setup Config').first().json;

return [{
  json: {
    pipeline_run_id: run.id,
    sop_id: run.sop_id,
    SUPABASE_URL: config.SUPABASE_URL,
    SUPABASE_ANON_KEY: config.SUPABASE_ANON_KEY,
    SUPABASE_SERVICE_ROLE_KEY: config.SUPABASE_SERVICE_ROLE_KEY,
    AZURE_BLOB_SAS_TOKEN: config.AZURE_BLOB_SAS_TOKEN,
    GCP_PROJECT_ID: config.GCP_PROJECT_ID,
    GCP_REGION: config.GCP_REGION,
  }
}];

const step = $input.first().json;
const config = $('Setup Config').first().json;

return [{
  json: {
    step_id: step.id,
    sequence: step.sequence,
    timestamp_start: step.timestamp_start,
    screenshot_url: step.screenshot_url,
    screenshot_width: step.screenshot_width || 1920,
    screenshot_height: step.screenshot_height || 1080,
    screenshot_url_with_sas: step.screenshot_url + '?' + config.AZURE_BLOB_SAS_TOKEN,
  }
}];

// Pass through Build Image URL data — no binary download needed.
// Gemini Vision now uses fileData.fileUri (HTTPS URL) instead of inlineData (base64).
const prevJson = $('Build Image URL').first().json;

return [{
  json: {
    step_id: prevJson.step_id,
    sequence: prevJson.sequence,
    screenshot_url: prevJson.screenshot_url,
    screenshot_width: prevJson.screenshot_width,
    screenshot_height: prevJson.screenshot_height,
    screenshot_url_with_sas: prevJson.screenshot_url_with_sas,
  }
}];

// Build Gemini request using fileData.fileUri (HTTPS URL) — avoids base64 binary corruption
// Vertex AI Gemini 2.0+ supports HTTPS URLs in fileData.fileUri
const prevData = $('Convert to Base64').first().json;

const prompt = `You are analyzing a screenshot from a software training video where a trainer is demonstrating a business process step by step.

1. Write one clear action-oriented sentence describing what is happening on screen (e.g., "The trainer opens the Aged Debtor report by navigating to the shared Credit Check folder").

2. Identify ONLY the 1 to 3 UI elements the trainer is DIRECTLY interacting with in this specific moment — the element being clicked, typed into, selected, or highlighted. Do NOT annotate background elements, toolbars, navigation menus, breadcrumbs, or any elements that are merely visible on screen but not being actively used in this step. When in doubt, fewer callouts are better than more. For each element provide:
   - label: the exact visible text of the element as it appears on screen (used to match against OCR)
   - element_type: one of: button, folder, cell, menu_item, icon, text_field, dropdown, link, tab, checkbox
   - target_x: estimated X pixel coordinate from left edge of image (used as fallback if OCR match fails)
   - target_y: estimated Y pixel coordinate from top edge of image (used as fallback if OCR match fails)
   - region_hint: brief location description (e.g., "top-right toolbar", "left sidebar third item")

Return ONLY valid JSON with no markdown code blocks:
{
  "description": "...",
  "ui_elements": [
    {
      "label": "...",
      "element_type": "...",
      "target_x": 0,
      "target_y": 0,
      "region_hint": "..."
    }
  ]
}`;

return [{
  json: {
    step_id: prevData.step_id,
    sequence: prevData.sequence,
    screenshot_url: prevData.screenshot_url,
    screenshot_width: prevData.screenshot_width,
    screenshot_height: prevData.screenshot_height,
    screenshot_url_with_sas: prevData.screenshot_url_with_sas,
    geminiBody: {
      contents: [{
        role: "user",
        parts: [
          {
            fileData: {
              mimeType: "image/png",
              fileUri: prevData.screenshot_url_with_sas
            }
          },
          { text: prompt }
        ]
      }],
      generationConfig: {
        temperature: 0.1,
        responseMimeType: "application/json"
      }
    }
  }
}];

const data = $input.first().json;
const prev = $('Build Gemini Request').first().json;

const raw = data.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  const match = raw.match(/\{[\s\S]*\}/);
  try {
    parsed = match ? JSON.parse(match[0]) : { description: raw, ui_elements: [] };
  } catch (e2) {
    parsed = { description: raw, ui_elements: [] };
  }
}

const description = parsed.description || '';
const elements = Array.isArray(parsed.ui_elements) ? parsed.ui_elements : [];

const callouts = elements.map((el, idx) => ({
  step_id: prev.step_id,
  callout_number: idx + 1,
  label: el.label || `Element ${idx + 1}`,
  element_type: el.element_type || 'button',
  target_x: Math.round(Number(el.target_x) || 0),
  target_y: Math.round(Number(el.target_y) || 0),
  gemini_region_hint: el.region_hint || '',
  confidence: 'gemini_only',
  match_method: 'gemini_coordinates',
}));

return [{
  json: {
    step_id: prev.step_id,
    sequence: prev.sequence,
    screenshot_url: prev.screenshot_url,
    screenshot_width: prev.screenshot_width,
    screenshot_height: prev.screenshot_height,
    screenshot_url_with_sas: prev.screenshot_url_with_sas,
    gemini_description: description,
    callouts: callouts,
    visionOCRBody: {
      requests: [{
        image: { source: { imageUri: prev.screenshot_url_with_sas } },
        features: [{ type: 'TEXT_DETECTION' }]
      }]
    },
  }
}];

const geminiData = $('Parse Gemini Response').first().json;
const visionData = $input.first().json;

const textAnnotations = visionData.responses?.[0]?.textAnnotations || [];
const ocrWords = textAnnotations.slice(1);

const imgWidth = geminiData.screenshot_width || 1920;
const imgHeight = geminiData.screenshot_height || 1080;

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  const dp = Array.from({length: m + 1}, () => Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = Math.min(
        dp[i-1][j] + 1,
        dp[i][j-1] + 1,
        dp[i-1][j-1] + (a[i-1] !== b[j-1] ? 1 : 0)
      );
    }
  }
  return dp[m][n];
}

function regionToApproxCoords(hint, w, h) {
  let x = w * 0.5, y = h * 0.5;
  const lower = (hint || '').toLowerCase();
  if (lower.includes('left'))   x = w * 0.15;
  if (lower.includes('right'))  x = w * 0.85;
  if (lower.includes('top'))    y = h * 0.15;
  if (lower.includes('bottom')) y = h * 0.85;
  if (lower.includes('center') || lower.includes('middle')) { x = w * 0.5; y = h * 0.5; }
  return { x: Math.round(x), y: Math.round(y) };
}

const elements = geminiData.callouts || [];

const matchedCallouts = elements.map(el => {
  const label = (el.label || '').toLowerCase().trim();
  let bestMatch = null;
  let bestScore = Infinity;
  let confidence = 'gemini_only';
  let matchMethod = 'gemini_coordinates';

  for (const ocr of ocrWords) {
    const ocrText = (ocr.description || '').toLowerCase().trim();
    if (!ocrText) continue;
    const vertices = ocr.boundingPoly?.vertices || [];
    if (vertices.length < 3) continue;
    const cx = Math.round(((vertices[0].x || 0) + (vertices[2].x || 0)) / 2);
    const cy = Math.round(((vertices[0].y || 0) + (vertices[2].y || 0)) / 2);

    if (ocrText === label || label.includes(ocrText) || ocrText.includes(label)) {
      if (!bestMatch || ocrText.length > (bestMatch.text || '').length) {
        bestMatch = { x: cx, y: cy, text: ocrText };
        confidence = 'ocr_exact';
        matchMethod = 'ocr_exact_text';
        bestScore = 0;
      }
      continue;
    }

    if (bestScore === 0) continue;
    const dist = levenshtein(ocrText, label);
    const threshold = Math.max(2, Math.floor(label.length * 0.3));
    if (dist <= threshold && dist < bestScore) {
      bestMatch = { x: cx, y: cy, text: ocrText };
      confidence = 'ocr_fuzzy';
      matchMethod = 'ocr_fuzzy_text';
      bestScore = dist;
    }
  }

  let coords;
  if (bestMatch) {
    coords = { x: bestMatch.x, y: bestMatch.y };
  } else if (el.target_x > 0 || el.target_y > 0) {
    coords = { x: el.target_x, y: el.target_y };
    matchMethod = 'gemini_coordinates';
  } else {
    coords = regionToApproxCoords(el.gemini_region_hint, imgWidth, imgHeight);
    matchMethod = 'gemini_region_estimate';
  }

  return {
    step_id: el.step_id,
    callout_number: el.callout_number,
    label: el.label,
    element_type: el.element_type,
    target_x: coords.x,
    target_y: coords.y,
    gemini_region_hint: el.gemini_region_hint,
    confidence: confidence,
    match_method: matchMethod,
    ocr_matched_text: bestMatch ? bestMatch.text : null,
  };
});

return [{
  json: {
    step_id: geminiData.step_id,
    sequence: geminiData.sequence,
    gemini_description: geminiData.gemini_description,
    callouts: matchedCallouts,
    callout_count: matchedCallouts.length,
    ocr_word_count: ocrWords.length,
  }
}];
